const body = $input.first().json.body || {};
const secret = $env.N8N_HEADER_AUTH_VALUE;
const received = $input.first().json.headers?.['x-videomill-auth'];

if (secret && received !== secret) {
  return [{ json: { error: 'Unauthorized' } }];
}

return [{ json: body }];

const item = $input.first().json;
const videoId = item.video_id;
const userId = item.user_id || 'unknown';

console.log('📌 Prepare Prompt:', { videoId, userId, topic: item.topic });

const prompt = `Create a viral video script about: ${item.topic || 'interesting topic'}. Return valid JSON with:
- title (string)
- description (string)
- hashtags (array of strings)
- scenes (array of objects, each with: narration, visual_description, duration_seconds, search_keywords array)

Create exactly 3-5 scenes, each 5-8 seconds. Use real content, no placeholders.`;

return [{ json: { video_id: videoId, user_id: userId, prompt: prompt, topic: item.topic } }];

