const content = $input.first().json.choices?.[0]?.message?.content || '{}';
let script = {};

try { script = JSON.parse(content); } catch(e) {
  console.error('❌ Parse error:', e.message);
  script = { title: 'Video', scenes: [] };
}

const inputItem = $input.first().json;
const videoId = inputItem.video_id;
const userId = inputItem.user_id;

console.log('✅ Script parsed:', { title: script.title, sceneCount: script.scenes?.length || 0, userId });

// Default scenes if empty - this fixes the 0.05s video issue!
if (!script.scenes || !Array.isArray(script.scenes) || script.scenes.length === 0) {
  console.log('⚠️ Empty scenes - using defaults');
  script.scenes = [
    { narration: 'Welcome to this video', visual_description: 'Open with engaging intro', duration_seconds: 5, search_keywords: ['intro', 'modern'] },
    { narration: 'Here is the main content', visual_description: 'Show relevant visuals', duration_seconds: 8, search_keywords: ['content', 'background'] },
    { narration: 'Thanks for watching', visual_description: 'Closing screen with CTA', duration_seconds: 5, search_keywords: [' Outro', 'outro'] }
  ];
}

return [{ json: { ...script, video_id: videoId, user_id: userId } }];
